#include <stdio.h>

enum Day {MON, TUE, WED, THU, FRI, SAT, SUN};
enum Weather {SUNNY = 1, CLOUDY = 2, RAINY = 3, SNOWY = 4};

int main() {
  enum Day today = WED;
  printf("Day index: %d\n", today);
  enum Weather w = RAINY;
  printf("Weather code: %d\n", w);
  if (today == SAT || today == SUN) {
    printf("Weekend!\n");
  } else {
    printf("Weekday\n");
  }
  return 0;
}
